module multi_pipe_4bit(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);

reg [3:0] reg_a, reg_b;
reg [7:0] reg_out;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg_a <= 4'b0;
        reg_b <= 4'b0;
        reg_out <= 8'b0;
    end else begin
        reg_a <= mul_a;
        reg_b <= mul_b;
        reg_out <= reg_a * reg_b;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 8'b0;
    end else begin
        mul_out <= reg_out;
    end
end

endmodule
